{
  "version": "Notebook/1.0",
  "items": [
    {
      "type": 1,
      "content": {
        "json": "## Threat Operations Dashboard No EDR AV Logs\nA single pane of glass for threat detection and response across host, identity, network, and cloud. Powered by native incident correlation, UEBA (User and Entity Behavior Analytics), ML anomalies, and Microsoft Defender Threat Intelligence (MDTI). Use the **Time Range** picker and the **tabs** below to pivot between the Overview, Host, Identity, Network, Cloud, and Sign-in Geography threat views."
      },
      "name": "header"
    },
    {
      "type": 9,
      "content": {
        "version": "KqlParameterItem/1.0",
        "parameters": [
          {
            "id": "a1b2c3d4-0001-0001-0001-000000000001",
            "version": "KqlParameterItem/1.0",
            "name": "TimeRange",
            "label": "Time Range",
            "type": 4,
            "isRequired": true,
            "isGlobal": true,
            "typeSettings": {
              "selectableValues": [
                { "durationMs": 86400000 },
                { "durationMs": 259200000 },
                { "durationMs": 604800000 },
                { "durationMs": 1209600000 },
                { "durationMs": 2592000000 },
                { "durationMs": 7776000000 }
              ],
              "allowCustom": true
            },
            "timeContext": { "durationMs": 2592000000 },
            "value": { "durationMs": 2592000000 }
          },
          {
            "id": "a1b2c3d4-0001-0001-0001-000000000002",
            "version": "KqlParameterItem/1.0",
            "name": "selectedTab",
            "type": 1,
            "isHiddenWhenLocked": true,
            "value": "1"
          }
        ],
        "style": "pills",
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces"
      },
      "name": "parameters"
    },
    {
      "type": 11,
      "content": {
        "version": "LinkItem/1.0",
        "style": "tabs",
        "links": [
          {
            "id": "a1b2c3d4-0002-0002-0002-000000000001",
            "cellValue": "selectedTab",
            "linkTarget": "parameter",
            "linkLabel": "Threat Overview",
            "subTarget": "1",
            "style": "link"
          },
          {
            "id": "a1b2c3d4-0002-0002-0002-000000000002",
            "cellValue": "selectedTab",
            "linkTarget": "parameter",
            "linkLabel": "Host Based Threats",
            "subTarget": "2",
            "style": "link"
          },
          {
            "id": "a1b2c3d4-0002-0002-0002-000000000003",
            "cellValue": "selectedTab",
            "linkTarget": "parameter",
            "linkLabel": "Identity & UEBA",
            "subTarget": "3",
            "style": "link"
          },
          {
            "id": "a1b2c3d4-0002-0002-0002-000000000004",
            "cellValue": "selectedTab",
            "linkTarget": "parameter",
            "linkLabel": "Network & Threat Intel",
            "subTarget": "4",
            "style": "link"
          },
          {
            "id": "a1b2c3d4-0002-0002-0002-000000000005",
            "cellValue": "selectedTab",
            "linkTarget": "parameter",
            "linkLabel": "Cloud & SaaS Activity",
            "subTarget": "5",
            "style": "link"
          },
          {
            "id": "a1b2c3d4-0002-0002-0002-000000000006",
            "cellValue": "selectedTab",
            "linkTarget": "parameter",
            "linkLabel": "Sign-in Geography",
            "subTarget": "6",
            "style": "link"
          },
          {
            "id": "a1b2c3d4-0002-0002-0002-000000000007",
            "cellValue": "selectedTab",
            "linkTarget": "parameter",
            "linkLabel": "Linux Operations",
            "subTarget": "7",
            "style": "link"
          },
          {
            "id": "a1b2c3d4-0002-0002-0002-000000000008",
            "cellValue": "selectedTab",
            "linkTarget": "parameter",
            "linkLabel": "Firewall (SonicWall CEF)",
            "subTarget": "8",
            "style": "link"
          }
        ]
      },
      "name": "tabs"
    },
    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "Threat Overview",
        "items": [
          {
            "type": 1,
            "content": {
              "json": "Whole environment threat posture in one view. Headline counts blend incidents, analytics alerts, UEBA risk, ML anomalies, and MDTI. The ATT&CK chart fuses analytic alerts with UEBA/ML anomaly tactics so leadership sees adversary behavior, not just log volume.",
              "style": "plain"
            },
            "name": "ov-info"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "union isfuzzy=true\n  (SecurityIncident | where TimeGenerated {TimeRange} | summarize arg_max(TimeGenerated, Status) by IncidentNumber | where Status != \"Closed\" | summarize Value = count() | extend Metric = \"Open Incidents\", Sort = 1),\n  (SecurityAlert | where TimeGenerated {TimeRange} | where AlertSeverity in (\"High\",\"Critical\") | summarize Value = count() | extend Metric = \"High/Critical Alerts\", Sort = 2),\n  (BehaviorAnalytics | where TimeGenerated {TimeRange} | where InvestigationPriority > 0 | summarize Value = count() | extend Metric = \"UEBA Risk Activities\", Sort = 3),\n  (Anomalies | where TimeGenerated {TimeRange} | summarize Value = count() | extend Metric = \"ML Anomalies\", Sort = 4),\n  (ThreatIntelIndicators | where TimeGenerated {TimeRange} | summarize Value = count() | extend Metric = \"Threat Intel Indicators\", Sort = 5),\n  (AADRiskyUsers | where TimeGenerated {TimeRange} | summarize Value = dcount(UserPrincipalName) | extend Metric = \"Risky Users\", Sort = 6)\n| project Metric, Value, Sort\n| sort by Sort asc",
              "size": 3,
              "title": "Threat Posture at a Glance",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "tiles",
              "tileSettings": {
                "titleContent": { "columnMatch": "Metric", "formatter": 1 },
                "leftContent": {
                  "columnMatch": "Value",
                  "formatter": 12,
                  "formatOptions": { "palette": "blue" },
                  "numberFormat": { "unit": 17, "options": { "style": "decimal", "maximumFractionDigits": 0 } }
                },
                "showBorder": true
              }
            },
            "name": "ov-kpis"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityIncident\n| where TimeGenerated {TimeRange}\n| summarize arg_min(TimeGenerated, Severity) by IncidentNumber\n| summarize Incidents = count() by bin(TimeGenerated, {TimeRange:grain}), Severity\n| where TimeGenerated < bin(now(), {TimeRange:grain})\n| order by TimeGenerated asc",
              "size": 0,
              "title": "Incidents Created Over Time (by Severity)",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart",
              "chartSettings": { "createOtherGroup": 0 }
            },
            "customWidth": "60",
            "name": "ov-incident-trend"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityAlert\n| where TimeGenerated {TimeRange}\n| summarize Count = count() by AlertSeverity",
              "size": 0,
              "title": "Alert Severity Mix",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "piechart"
            },
            "customWidth": "40",
            "name": "ov-severity-mix"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "union isfuzzy=true\n  (SecurityAlert | where TimeGenerated {TimeRange} | where isnotempty(Tactics) | extend T = split(Tactics, \",\")),\n  (Anomalies | where TimeGenerated {TimeRange} | where isnotempty(Tactics) | extend T = split(Tactics, \";\"))\n| mv-expand Tactic = T to typeof(string)\n| extend Tactic = trim(@\"\\s+\", Tactic)\n| where isnotempty(Tactic)\n| summarize Detections = count() by Tactic\n| sort by Detections desc",
              "size": 0,
              "title": "MITRE ATT&CK Tactics Observed (Alerts + UEBA/ML Anomalies)",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart"
            },
            "customWidth": "60",
            "name": "ov-tactics"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityAlert\n| where TimeGenerated {TimeRange}\n| summarize Alerts = count(), LastSeen = max(TimeGenerated) by AlertName, ProductName, AlertSeverity\n| top 20 by Alerts desc",
              "size": 0,
              "title": "Top Detections Firing",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "Alerts", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 1000,
                "sortBy": [ { "itemKey": "Alerts", "sortOrder": 2 } ]
              },
              "sortBy": [ { "itemKey": "Alerts", "sortOrder": 2 } ]
            },
            "customWidth": "40",
            "name": "ov-top-detections"
          }
        ]
      },
      "conditionalVisibility": { "parameterName": "selectedTab", "comparison": "isEqualTo", "value": "1" },
      "name": "group-overview"
    },
    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "Host Based Threats",
        "items": [
          {
            "type": 1,
            "content": {
              "json": "Threat activity from Windows servers and workstations onboarded to Azure Arc with the Azure Monitor Agent (AMA), streamed through the **Windows Security Events via AMA** connector. No Microsoft Defender for Endpoint and no Defender for Identity. The core panes are built on the **SecurityEvent** table and are organised around what a threat actor actually does on a host: gain access with credentials, run tooling, move laterally, escalate privilege, establish persistence, and tamper with logging to evade detection. The Adversary Tactics chart maps raw Windows Event IDs to MITRE ATT&CK tactics so you read attacker behaviour, not just log volume. The network edge snapshot at the bottom surfaces the new SonicWall firewall feed (CEF via AMA) landing in **CommonSecurityLog**, with the full firewall analysis on the dedicated Firewall tab. Linux hosts have their own Linux Operations tab.",
              "style": "plain"
            },
            "name": "host-info"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "union isfuzzy=true\n  (SecurityEvent | where TimeGenerated {TimeRange} | summarize Value = dcount(Computer) | extend Metric = 'Windows Hosts Logging', Sort = 1),\n  (SecurityEvent | where TimeGenerated {TimeRange} | where EventID == 4625 | summarize Value = count() | extend Metric = 'Failed Logons (4625)', Sort = 2),\n  (SecurityEvent | where TimeGenerated {TimeRange} | where EventID == 4672 | summarize Value = count() | extend Metric = 'Privileged Logons (4672)', Sort = 3),\n  (SecurityEvent | where TimeGenerated {TimeRange} | where EventID == 4648 | summarize Value = count() | extend Metric = 'Explicit Cred Use (4648)', Sort = 4),\n  (SecurityEvent | where TimeGenerated {TimeRange} | where EventID == 4769 | summarize Value = count() | extend Metric = 'Kerberos Tickets (4769)', Sort = 5),\n  (SecurityEvent | where TimeGenerated {TimeRange} | where EventID == 4688 | summarize Value = count() | extend Metric = 'Process Creations (4688)', Sort = 6)\n| project Metric, Value, Sort\n| sort by Sort asc",
              "size": 3,
              "title": "Host Threat Snapshot (Windows Security Events via AMA)",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "tiles",
              "tileSettings": {
                "titleContent": { "columnMatch": "Metric", "formatter": 1 },
                "leftContent": {
                  "columnMatch": "Value",
                  "formatter": 12,
                  "formatOptions": { "palette": "green" },
                  "numberFormat": { "unit": 17, "options": { "style": "decimal", "maximumFractionDigits": 0 } }
                },
                "showBorder": true
              }
            },
            "name": "host-kpis"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityEvent\n| where TimeGenerated {TimeRange}\n| where EventID in (4625, 4771, 4776, 4648, 4769, 4768, 4698, 4699, 4702, 4697, 7045, 4720, 4722, 4724, 4728, 4732, 4756, 1102, 4719, 4688, 4798)\n| extend Tactic = case(\n    EventID in (4625, 4771, 4776), 'Credential Access',\n    EventID in (4648, 4769, 4768), 'Lateral Movement',\n    EventID in (4698, 4699, 4702, 4697, 7045, 4720, 4722, 4724, 4728, 4732, 4756), 'Persistence',\n    EventID in (1102, 4719), 'Defense Evasion',\n    EventID == 4688, 'Execution',\n    EventID == 4798, 'Discovery',\n    'Other')\n| summarize Events = count() by Tactic\n| sort by Events desc",
              "size": 0,
              "title": "Adversary Tactics Observed (Windows Event IDs Mapped to MITRE ATT&CK)",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart",
              "chartSettings": { "createOtherGroup": 0 }
            },
            "name": "host-attack-tactics"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityEvent\n| where TimeGenerated {TimeRange}\n| where EventID in (4624, 4625)\n| summarize SuccessfulLogons = countif(EventID == 4624), FailedLogons = countif(EventID == 4625) by bin(TimeGenerated, {TimeRange:grain})\n| where TimeGenerated < bin(now(), {TimeRange:grain})\n| order by TimeGenerated asc",
              "size": 0,
              "title": "Logon Activity Trend - Success vs Failed (Brute Force / Spray Signal)",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "linechart"
            },
            "customWidth": "60",
            "name": "host-logon-trend"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityEvent\n| where TimeGenerated {TimeRange}\n| where EventID == 4624\n| extend LogonTypeName = case(\n    LogonType == 2, '2 Interactive',\n    LogonType == 3, '3 Network',\n    LogonType == 4, '4 Batch',\n    LogonType == 5, '5 Service',\n    LogonType == 7, '7 Unlock',\n    LogonType == 8, '8 NetworkCleartext',\n    LogonType == 9, '9 NewCredentials (RunAs)',\n    LogonType == 10, '10 RemoteInteractive (RDP)',\n    LogonType == 11, '11 CachedInteractive',\n    strcat('Type ', tostring(LogonType)))\n| summarize Count = count() by LogonTypeName\n| sort by Count desc",
              "size": 0,
              "title": "Logon Type Distribution (Network & RDP = Lateral Movement Surface)",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "piechart"
            },
            "customWidth": "40",
            "name": "host-logontype"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityEvent\n| where TimeGenerated {TimeRange}\n| where EventID == 4672\n| summarize PrivilegedLogons = count(), Accounts = dcount(SubjectUserName), LastSeen = max(TimeGenerated) by Computer\n| top 15 by PrivilegedLogons desc",
              "size": 0,
              "title": "Top Hosts by Privileged Logon (4672) Admin Rights Asserted",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "PrivilegedLogons", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 1000,
                "sortBy": [ { "itemKey": "PrivilegedLogons", "sortOrder": 2 } ]
              }
            },
            "customWidth": "50",
            "name": "host-priv-hosts"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityEvent\n| where TimeGenerated {TimeRange}\n| where EventID == 4672\n| where SubjectUserName !endswith '$'\n| summarize PrivilegedLogons = count(), Hosts = dcount(Computer), FirstSeen = min(TimeGenerated), LastSeen = max(TimeGenerated) by Account = SubjectUserName\n| top 20 by PrivilegedLogons desc",
              "size": 0,
              "title": "Accounts Using Privileged Logon Rights (4672) Privilege Escalation Watch",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "PrivilegedLogons", "formatter": 8, "formatOptions": { "palette": "orange" } },
                  { "columnMatch": "Hosts", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "FirstSeen", "formatter": 6 },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 1000,
                "sortBy": [ { "itemKey": "PrivilegedLogons", "sortOrder": 2 } ]
              }
            },
            "customWidth": "50",
            "name": "host-priv-accounts"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityEvent\n| where TimeGenerated {TimeRange}\n| where EventID == 4648\n| summarize Uses = count(), DistinctTargets = dcount(TargetUserName), TargetAccounts = make_set(TargetUserName, 10), Hosts = dcount(Computer), FirstSeen = min(TimeGenerated), LastSeen = max(TimeGenerated) by SourceAccount = SubjectUserName\n| top 20 by Uses desc",
              "size": 0,
              "title": "Explicit Credential Use (4648) RunAs / Pass-the-Hash / Lateral Movement",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "Uses", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "DistinctTargets", "formatter": 8, "formatOptions": { "palette": "orange" } },
                  { "columnMatch": "FirstSeen", "formatter": 6 },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 1000,
                "sortBy": [ { "itemKey": "Uses", "sortOrder": 2 } ]
              }
            },
            "customWidth": "50",
            "name": "host-explicit-cred"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityEvent\n| where TimeGenerated {TimeRange}\n| where EventID == 4769\n| where ServiceName != 'krbtgt'\n| summarize Requests = count(), Services = dcount(ServiceName), ServicesRequested = make_set(ServiceName, 10), Hosts = dcount(Computer), LastSeen = max(TimeGenerated) by Account = TargetAccount\n| top 20 by Requests desc",
              "size": 0,
              "title": "Kerberos Service Ticket Requests (4769) Kerberoasting Hunt",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "Requests", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "Services", "formatter": 8, "formatOptions": { "palette": "orange" } },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 1000,
                "sortBy": [ { "itemKey": "Requests", "sortOrder": 2 } ]
              }
            },
            "customWidth": "50",
            "name": "host-kerberos"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityEvent\n| where TimeGenerated {TimeRange}\n| where EventID == 4688\n| extend Proc = tolower(tostring(split(NewProcessName, \"\\\\\")[-1]))\n| extend Parent = tolower(tostring(split(ParentProcessName, \"\\\\\")[-1]))\n| where isnotempty(Proc)\n| summarize Executions = count(), Hosts = dcount(Computer), Accounts = dcount(SubjectUserName), ParentProcesses = dcount(Parent), TopParent = arg_max(TimeGenerated, Parent).Parent, FirstSeen = min(TimeGenerated), LastSeen = max(TimeGenerated) by Proc\n| top 25 by Executions desc",
              "size": 0,
              "title": "Process Creation Inventory (4688) Hunt for the Unusual",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "Executions", "formatter": 8, "formatOptions": { "palette": "blue" } },
                  { "columnMatch": "Hosts", "formatter": 8, "formatOptions": { "palette": "green" } },
                  { "columnMatch": "FirstSeen", "formatter": 6 },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 5000,
                "sortBy": [ { "itemKey": "Executions", "sortOrder": 2 } ]
              }
            },
            "customWidth": "50",
            "name": "host-processes"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityEvent\n| where TimeGenerated {TimeRange}\n| where EventID == 4688\n| extend Proc = tolower(tostring(split(NewProcessName, \"\\\\\")[-1]))\n| where Proc in ('powershell.exe', 'pwsh.exe', 'cmd.exe', 'wmic.exe', 'rundll32.exe', 'mshta.exe', 'regsvr32.exe', 'certutil.exe', 'bitsadmin.exe', 'cscript.exe', 'wscript.exe', 'psexec.exe', 'net.exe', 'net1.exe', 'schtasks.exe', 'sc.exe', 'reg.exe', 'vssadmin.exe', 'wevtutil.exe', 'whoami.exe', 'nltest.exe')\n| extend Parent = tolower(tostring(split(ParentProcessName, \"\\\\\")[-1]))\n| summarize Executions = count(), Hosts = dcount(Computer), Accounts = dcount(SubjectUserName), Parents = make_set(Parent, 8), LastSeen = max(TimeGenerated) by Proc\n| sort by Executions desc",
              "size": 0,
              "title": "LOLBin & Dual-Use Tool Execution (4688) Living-off-the-Land Tradecraft",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "Executions", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "Hosts", "formatter": 8, "formatOptions": { "palette": "orange" } },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 5000,
                "sortBy": [ { "itemKey": "Executions", "sortOrder": 2 } ]
              }
            },
            "customWidth": "50",
            "name": "host-lolbins"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityEvent\n| where TimeGenerated {TimeRange}\n| where EventID in (4720, 4722, 4724, 4726, 4738, 4728, 4732, 4756, 4740, 1102, 4719, 4698, 4699, 4702, 4697, 7045)\n| extend Activity = case(\n    EventID == 4720, 'Account Created',\n    EventID == 4722, 'Account Enabled',\n    EventID == 4724, 'Password Reset Attempt',\n    EventID == 4726, 'Account Deleted',\n    EventID == 4738, 'Account Changed',\n    EventID == 4728, 'Added to Global Security Group',\n    EventID == 4732, 'Added to Local Security Group',\n    EventID == 4756, 'Added to Universal Security Group',\n    EventID == 4740, 'Account Lockout',\n    EventID == 1102, 'Audit Log Cleared',\n    EventID == 4719, 'Audit Policy Changed',\n    EventID == 4698, 'Scheduled Task Created',\n    EventID == 4699, 'Scheduled Task Deleted',\n    EventID == 4702, 'Scheduled Task Updated',\n    EventID == 4697, 'Service Installed',\n    EventID == 7045, 'Service Installed (SCM)',\n    strcat('Event ', tostring(EventID)))\n| summarize Count = count(), Hosts = dcount(Computer), Accounts = dcount(SubjectUserName), LastSeen = max(TimeGenerated) by Activity, EventID\n| sort by Count desc",
              "size": 0,
              "title": "Security Sensitive Events - Persistence, PrivEsc & Defense Evasion",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "Count", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "EventID", "formatter": 1 },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 5000,
                "sortBy": [ { "itemKey": "Count", "sortOrder": 2 } ]
              }
            },
            "customWidth": "50",
            "name": "host-sensitive-events"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityEvent\n| where TimeGenerated {TimeRange}\n| where EventID == 4798\n| summarize Enumerations = count(), TargetAccounts = dcount(TargetAccount), Hosts = dcount(Computer), FirstSeen = min(TimeGenerated), LastSeen = max(TimeGenerated) by Actor = SubjectUserName\n| top 20 by Enumerations desc",
              "size": 0,
              "title": "Local Group Membership Enumeration (4798) Discovery / Recon",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "Enumerations", "formatter": 8, "formatOptions": { "palette": "purple" } },
                  { "columnMatch": "Hosts", "formatter": 8, "formatOptions": { "palette": "orange" } },
