          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SecurityEvent\n| where TimeGenerated {TimeRange}\n| where EventID == 4688\n| extend Proc = tolower(tostring(split(NewProcessName, \"\\\\\")[-1]))\n| where Proc in ('powershell.exe', 'pwsh.exe')\n| where TokenElevationType has '1937' or TokenElevationType has 'Full'\n| extend Parent = tolower(tostring(split(ParentProcessName, \"\\\\\")[-1]))\n| summarize Executions = count(), Hosts = dcount(Computer), HostList = make_set(Computer, 6), ParentProcs = make_set(Parent, 8), DistinctParents = dcount(Parent), FirstSeen = min(TimeGenerated), LastSeen = max(TimeGenerated) by Account = SubjectUserName, Proc\n| top 25 by Executions desc",
              "size": 0,
              "title": "Elevated PowerShell Execution (4688 Admin Token) Privilege Escalation Watch",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "Executions", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "Hosts", "formatter": 8, "formatOptions": { "palette": "orange" } },
                  { "columnMatch": "DistinctParents", "formatter": 8, "formatOptions": { "palette": "orange" } },
                  { "columnMatch": "FirstSeen", "formatter": 6 },
