          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "union isfuzzy=true\n  (CommonSecurityLog | where TimeGenerated {TimeRange} | summarize Value = dcount(DeviceName) | extend Metric = 'Firewalls Reporting (CEF/AMA)', Sort = 1),\n  (CommonSecurityLog | where TimeGenerated {TimeRange} | summarize Value = count() | extend Metric = 'Firewall Events', Sort = 2),\n  (CommonSecurityLog | where TimeGenerated {TimeRange} | extend ActRaw = iif(isnotempty(DeviceAction), DeviceAction, extract(@'fw_action=\"([^\"]+)\"', 1, AdditionalExtensions)) | where tolower(ActRaw) in ('deny','denied','drop','dropped','block','blocked') | summarize Value = count() | extend Metric = 'Denied / Blocked', Sort = 3),\n  (CommonSecurityLog | where TimeGenerated {TimeRange} | summarize Value = dcount(SourceIP) | extend Metric = 'Distinct Source IPs', Sort = 4)\n| project Metric, Value, Sort\n| sort by Sort asc",
