            "name": "id-ueba-activity"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "AADUserRiskEvents\n| where TimeGenerated {TimeRange}\n| summarize Count = count() by bin(TimeGenerated, {TimeRange:grain}), RiskEventType\n| where TimeGenerated < bin(now(), {TimeRange:grain})\n| order by TimeGenerated asc",
              "size": 0,
