          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "AADRiskyUsers\n| where TimeGenerated {TimeRange}\n| where RiskState in (\"atRisk\",\"confirmedCompromised\")\n| summarize arg_min(TimeGenerated, RiskLevel) by UserPrincipalName\n| summarize NewRiskyUsers = count() by bin(TimeGenerated, 1d)\n| where TimeGenerated < bin(now(), 1d)\n| order by TimeGenerated asc",
              "size": 0,
