          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "AADUserRiskEvents\n| where TimeGenerated {TimeRange}\n| where isnotempty(RiskEventType)\n| summarize Detections = count() by RiskEventType\n| sort by Detections desc",
              "size": 0,
              "title": "Risk Detection Types",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart"
            },
            "customWidth": "34",
            "name": "id-detection-type-mix"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "AADUserRiskEvents\n| where TimeGenerated {TimeRange}\n| extend City = tostring(Location.city), State = tostring(Location.state), Country = tostring(Location.countryOrRegion)\n| extend Place = strcat(City, iff(isnotempty(State), strcat(\", \", State), \"\"), iff(isnotempty(Country), strcat(\", \", Country), \"\"))\n| project DetectedDateTime, User = UserPrincipalName, IpAddress, Location = Place, DetectionType = RiskEventType, Timing = DetectionTimingType, RiskLevel, RiskState, Source\n| order by DetectedDateTime desc",
              "size": 0,
              "title": "Risk Detections Feed (Live from Entra ID Protection)",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "DetectedDateTime", "formatter": 6 },
                  { "columnMatch": "DetectionType", "formatter": 1 },
                  {
                    "columnMatch": "RiskLevel",
