              "query": "let tiIps = ThreatIntelIndicators\n  | where TimeGenerated {TimeRange}\n  | where ObservableKey has \"ipv4-addr\"\n  | distinct ObservableValue;\nunion isfuzzy=true\n  (SigninLogs | where TimeGenerated {TimeRange} | project IP = IPAddress, Source = \"Entra Sign in\", TimeGenerated),\n  (AADNonInteractiveUserSignInLogs | where TimeGenerated {TimeRange} | project IP = IPAddress, Source = \"Non Interactive Sign in\", TimeGenerated),\n  (MicrosoftGraphActivityLogs | where TimeGenerated {TimeRange} | project IP = tostring(IPAddress), Source = \"Graph API\", TimeGenerated),\n  (AzureActivity | where TimeGenerated {TimeRange} | project IP = CallerIpAddress, Source = \"Azure Control Plane\", TimeGenerated),\n  (OfficeActivity | where TimeGenerated {TimeRange} | project IP = tostring(extract(@\"(\\d+\\.\\d+\\.\\d+\\.\\d+)\", 1, ClientIP)), Source = \"Office 365\", TimeGenerated)\n| where isnotempty(IP) and IP in (tiIps)\n| summarize Hits = count() by bin(TimeGenerated, {TimeRange:grain}), Source\n| where TimeGenerated < bin(now(), {TimeRange:grain})\n| order by TimeGenerated asc",
              "size": 0,
