              "query": "MicrosoftGraphActivityLogs\n| where TimeGenerated {TimeRange}\n| summarize Calls = count() by StatusClass = strcat(substring(tostring(ResponseStatusCode), 0, 1), \"xx\")\n| order by StatusClass asc",
