            "content": {
              "version": "KqlItem/1.0",
              "query": "MicrosoftGraphActivityLogs\n| where TimeGenerated {TimeRange}\n| where isnotempty(UserAgent)\n| summarize Calls = count() by UserAgent\n| top 15 by Calls desc",
