            "name": "cloud-kpis"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "union isfuzzy=true\n  (OfficeActivity | where TimeGenerated {TimeRange} | where Operation in (\"New-InboxRule\",\"Set-InboxRule\",\"UpdateInboxRules\",\"Add-MailboxPermission\") | extend Category = \"Mailbox/Rule Ops\"),\n  (AuditLogs | where TimeGenerated {TimeRange} | where OperationName has \"Consent to application\" | extend Category = \"App Consent\"),\n  (AuditLogs | where TimeGenerated {TimeRange} | where OperationName has \"Add member to role\" | extend Category = \"Privileged Role Add\")\n| summarize Count = count() by bin(TimeGenerated, {TimeRange:grain}), Category\n| where TimeGenerated < bin(now(), {TimeRange:grain})\n| order by TimeGenerated asc",
              "size": 0,
              "title": "Cloud Threat Signals Over Time",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "areachart"
